                fallback: CATALOG_APPROVAL_STATUS.APPROVED,
            });
            const relation = await validateScreenSizeRelations({ categoryId: nextCategoryId, brandId: nextBrandId });
            if (!relation.ok) throw new Error(relation.reason || 'Invalid relation');
