    withPublicCanonicalLocationFilter,
    buildNormalizedFromLocationDoc,
    mapLocationDocsToResponses
} from './_shared/locationServiceBase';
import type {
    LocationInputObject,
    GeoJSONPoint,
    NormalizedLocationResponse
} from './_shared/locationServiceBase';
