export const getNearbyLocations = async (
    lat: number,
    lng: number,
    radiusKm: number
): Promise<NormalizedLocationResponse[]> => {
    if (!Number.isFinite(lat) || !Number.isFinite(lng)) {
        throw new AppError('Invalid coordinates', 400, 'INVALID_COORDINATES');
    }
    if (lat < -90 || lat > 90 || lng < -180 || lng > 180) {
        throw new AppError('Coordinates out of range', 400, 'INVALID_COORDINATES');
    }
    if (lat === 0 && lng === 0) {
        throw new AppError('Null-island coordinates are not allowed', 400, 'INVALID_COORDINATES');
    }

    const safeRadiusKm = Math.min(Math.max(Number(radiusKm) || 10, 1), 500);
    const nearby = await Location.find({
        isActive: true,
        coordinates: {
            $near: {
                $geometry: { type: 'Point', coordinates: [lng, lat] },
                $maxDistance: safeRadiusKm * 1000
            }
        }
    })
        .select('name country level coordinates isPopular isActive verificationStatus parentId path')
        .limit(50)
        .lean();

    return mapLocationDocsToResponses(nearby);
};

export const getHierarchy = async (
    parentId?: string,
    level?: string,
    state?: string
): Promise<NormalizedLocationResponse[]> => {
    const query: Record<string, unknown> = { isActive: true };
    const normalizedLevel = normalizeLocationLevel(level);
    if (normalizedLevel) {
        query.level = normalizedLevel;
    }

    if (parentId && mongoose.Types.ObjectId.isValid(parentId)) {
        query.path = new mongoose.Types.ObjectId(parentId);
    } else {
        const normalizedState = toTitleCase(asString(state) || '');
        if (normalizedState) {
            if (normalizedLevel === 'state') {
                query.name = new RegExp(`^${escapeRegExp(normalizedState)}$`, 'i');
            } else {
                const stateAnchor = await Location.findOne({
                    isActive: true,
                    level: 'state',
                    name: new RegExp(`^${escapeRegExp(normalizedState)}$`, 'i')
                })
                    .select('_id')
                    .lean<{ _id: mongoose.Types.ObjectId } | null>();

                if (!stateAnchor) {
                    return [];
                }

                query.path = stateAnchor._id;
            }
        }
    }

    const hierarchyItems = await Location.find(query)
        .select('name country level coordinates isPopular isActive verificationStatus parentId path')
        .sort({ isPopular: -1, priority: -1, name: 1 })
        .limit(200)
        .lean();

    return mapLocationDocsToResponses(hierarchyItems);
};

export const getDefaultCenterLocation = async (
    configuredCenter?: { lat?: number; lng?: number }
): Promise<(NormalizedLocationResponse & { source: 'default' }) | null> => {
    const configuredLat = Number(configuredCenter?.lat);
    const configuredLng = Number(configuredCenter?.lng);
    const hasConfiguredCenter =
        Number.isFinite(configuredLat) &&
        Number.isFinite(configuredLng) &&
        (configuredLat !== 0 || configuredLng !== 0);

    if (hasConfiguredCenter) {
        const nearest = await Location.findOne(withPublicCanonicalLocationFilter({
            coordinates: {
                $near: {
                    $geometry: { type: 'Point', coordinates: [configuredLng, configuredLat] },
                    $maxDistance: 250000,
                },
            },
        }))
            .select('name country level coordinates isPopular isActive verificationStatus parentId path')
            .lean();

        if (nearest) {
            const [mappedNearest] = await mapLocationDocsToResponses([nearest]);
            if (!mappedNearest) {
                return null;
            }
            return {
                ...mappedNearest,
                source: 'default',
            };
        }

        return {
            ...formatLocationResponse({
                name: 'Default Center',
                display: 'Default Center',
                city: 'Default Center',
                state: '',
                country: 'Unknown',
                level: 'city',
                coordinates: {
                    type: 'Point',
                    coordinates: [configuredLng, configuredLat],
                },
            }),
            source: 'default',
        };
    }

    const fallbackLocation = await Location.findOne(
        withPublicCanonicalLocationFilter({ level: 'city' as const, isPopular: true })
    )
        .select('name country level coordinates isPopular isActive verificationStatus parentId path')
        .sort({ priority: -1, name: 1 })
        .lean();

    if (fallbackLocation) {
        const [mappedFallbackLocation] = await mapLocationDocsToResponses([fallbackLocation]);
        if (!mappedFallbackLocation) {
            return null;
        }
        return {
            ...mappedFallbackLocation,
            source: 'default',
        };
    }

    const anyActiveLocation = await Location.findOne({ isActive: true, level: 'city' })
        .select('name country level coordinates isPopular isActive verificationStatus parentId path')
        .sort({ priority: -1, name: 1 })
        .lean();

    if (anyActiveLocation) {
        const [mappedActiveLocation] = await mapLocationDocsToResponses([anyActiveLocation]);
        if (!mappedActiveLocation) {
            return null;
        }
        return {
            ...mappedActiveLocation,
            source: 'default',
        };
    }

    return null;
};

export const deriveLocationMetadata = async (
    locationId?: string | mongoose.Types.ObjectId,
    rawCoordinates?: unknown
): Promise<{ city?: string; state?: string; coordinates?: GeoJSONPoint }> => {
    let city: string | undefined;
    let state: string | undefined;
    let coordinates: GeoJSONPoint | undefined;

    if (rawCoordinates) {
        try {
            const { normalizeGeoPoint } = await import('./_shared/locationServiceBase').then(m => m as { normalizeGeoPoint?: (input: unknown) => GeoJSONPoint })
            if (normalizeGeoPoint) {
                coordinates = normalizeGeoPoint(rawCoordinates);
            }
        } catch (e) {
            coordinates = undefined;
        }
    }

    if (!locationId) {
        return { city, state, coordinates };
    }

    try {
        const id = typeof locationId === 'string' ? new mongoose.Types.ObjectId(locationId) : locationId;
        const loc = await Location.findById(id).select('name level parentId coordinates').lean<{ 
            _id: mongoose.Types.ObjectId; 
            name: string; 
            level: string; 
            parentId?: mongoose.Types.ObjectId; 
            coordinates?: GeoJSONPoint;
        } | null>();

        if (!loc) {
            return { city, state, coordinates };
        }

        if (!coordinates && loc.coordinates) {
            coordinates = loc.coordinates;
        }

        if (loc.level === 'city') {
            city = loc.name;
            if (loc.parentId) {
                const parent = await Location.findById(loc.parentId).select('name level').lean<{ name: string; level: string } | null>();
                if (parent && parent.level === 'state') state = parent.name;
            }
        } else if (loc.level === 'state') {
            state = loc.name;
        } else if (loc.level === 'area' && loc.parentId) {
            const cityDoc = await Location.findById(loc.parentId).select('name parentId level').lean<{ name: string; parentId?: mongoose.Types.ObjectId; level: string } | null>();
            if (cityDoc && cityDoc.level === 'city') {
                city = cityDoc.name;
                if (cityDoc.parentId) {
                    const stateDoc = await Location.findById(cityDoc.parentId).select('name level').lean<{ name: string; level: string } | null>();
                    if (stateDoc && stateDoc.level === 'state') state = stateDoc.name;
                }
            }
        }
    } catch (e) {
        // Suppress
    }

    return { city, state, coordinates };
};

import type { Document, Model } from 'mongoose';
import { Request } from 'express';
import logger from '../logger';
import { getAdminConnection, getUserConnection } from '../../config/db';
import { castCatalogQueryIds, summarizeCatalogReadDiff, recordCatalogReadDiff } from '../catalogShadowRead';

export const CATALOG_MODELS = ['Category', 'Brand', 'Model', 'ServiceType', 'ScreenSize', 'SparePart'];

export const ensureAdminCatalogModel = <T extends Document>(model: Model<T>): Model<T> => {
    const adminConn = getAdminConnection();
    const userConn = getUserConnection();
    for (const modelName of CATALOG_MODELS) {
        const userModel = userConn.models[modelName] as Model<Document> | undefined;
        if (userModel && !adminConn.models[modelName]) adminConn.model(modelName, userModel.schema, userModel.collection.name);
    }
    return (adminConn.models[model.modelName] as Model<T> | undefined) || adminConn.model<T>(model.modelName, model.schema, model.collection.name);
};

export const readAdminCatalogPage = async (params: {
    model: Model<Document>; query: Record<string, unknown>; sort: Record<string, 1 | -1>; skip: number; limit: number; populate?: unknown; select?: string; includeDeleted?: boolean;
}) => {
    const adminModel = ensureAdminCatalogModel(params.model);
    const adminQuery = castCatalogQueryIds(params.query) as Record<string, unknown>;
    const findQuery = adminModel.find(adminQuery).skip(params.skip).limit(params.limit).sort(params.sort);
    if (params.includeDeleted) findQuery.setOptions({ withDeleted: true });
    if (params.populate) (findQuery as any).populate(params.populate);
    if (params.select) findQuery.select(params.select);
    const countQuery = adminModel.countDocuments(adminQuery);
    if (params.includeDeleted) countQuery.setOptions({ withDeleted: true });
    return Promise.all([findQuery, countQuery]);
};

export const tryAdminCatalogReadSwitch = async <T extends Document>(params: {
    req: Request; model: Model<T>; query: Record<string, unknown>; sort: Record<string, 1 | -1>; skip: number; limit: number; populate?: unknown; select?: string; includeDeleted?: boolean; transformResponse?: (items: unknown[]) => unknown | Promise<unknown>; userItems: unknown[]; userTotal: number;
}): Promise<{ items: unknown[]; total: number } | null> => {
    try {
        const [adminItems, adminTotal] = await readAdminCatalogPage({ model: params.model as any, query: params.query, sort: params.sort, skip: params.skip, limit: params.limit, populate: params.populate, select: params.select, includeDeleted: params.includeDeleted });
        const rai = params.transformResponse ? await params.transformResponse(adminItems as unknown[]) : adminItems as unknown[];
        if (!Array.isArray(rai)) return null;
        const diff = summarizeCatalogReadDiff(params.userItems as Record<string, unknown>[], rai as Record<string, unknown>[]);
        if (!diff.mismatch && params.userTotal === adminTotal) return { items: rai, total: adminTotal };
        await recordCatalogReadDiff({ modelName: params.model.modelName, query: params.query, userRows: params.userItems as Record<string, unknown>[], adminRows: rai as Record<string, unknown>[], requestPath: params.req.originalUrl || params.req.path, requestMethod: params.req.method });
        logger.warn('[CatalogReadSwitch] Falling back', { requestPath: params.req.originalUrl || params.req.path, modelName: params.model.modelName, userTotal: params.userTotal, adminTotal, summary: diff.summary });
        return null;
    } catch (error) {
        logger.warn('[CatalogReadSwitch] Admin read failed', { requestPath: params.req.originalUrl || params.req.path, modelName: params.model.modelName, error: error instanceof Error ? error.message : String(error) });
        return null;
    }
};

export const parseSortQuery = (rawSort: unknown, defaultSort: Record<string, 1 | -1>): Record<string, 1 | -1> => {
    if (typeof rawSort !== 'string' || rawSort.trim().length === 0) return defaultSort;
    const sort: Record<string, 1 | -1> = {};
    for (const segment of rawSort.split(',').map((s) => s.trim()).filter(Boolean)) {
        const dir: 1 | -1 = segment.startsWith('-') ? -1 : 1;
        const field = segment.replace(/^-/, '');
        if (!/^[a-zA-Z0-9_.]+$/.test(field)) continue;
        sort[field] = dir;
    }
    return Object.keys(sort).length > 0 ? sort : defaultSort;
};

import { Request, Response } from 'express';
import type { Document, Model } from 'mongoose';
import { LISTING_TYPE_VALUES, type ListingTypeValue } from '@esparex/shared';
import { getPaginationParams, sendPaginatedResponse, sendSuccessResponse, sendAdminError } from '../adminBaseController';
import { getCache, setCache, CACHE_TTLS } from '../redisCache';
import { FeatureFlag, isEnabled } from '../../config/featureFlags';
import { buildRegexSearchClauses, rankCatalogSearchResults, recordCatalogSearchTelemetry, shouldSuppressAutocomplete, tryAtlasCatalogSearch } from '../../services/catalog/CatalogSearchGovernanceService';
import { runCatalogShadowRead } from '../catalogShadowRead';
import type { ContentOptions } from './types';
import { CATALOG_MODELS, parseSortQuery, tryAdminCatalogReadSwitch } from './helpers';

const AF = new Set(['status','isActive','categoryId','categoryIds','brandId','modelId','parentModelId','variantOfModelId','variantModelId','type','needsReview','suggestedBy','createdBy','listingType']);
const IG = new Set(['page','limit','q','search','includeDeleted','sort','order','tab','view']);

export async function handlePaginatedContent<T extends Document>(req: Request, res: Response, model: Model<T>, options: ContentOptions = {}) {
    try {
        const user = (req as any).user;
        const isAdmin = Boolean((req as any).admin) || user?.role === 'admin' || user?.role === 'super_admin';
        const isUrlAdmin = req.originalUrl.includes('/admin');
        const { searchFields = ['name'], defaultSort = { name: 1 }, publicQuery = { isActive: true }, adminQuery = {}, populate, select, transformResponse, queryParams } = options;
        const eq = (queryParams || req.query) as Record<string, unknown>;
        const isCM = CATALOG_MODELS.includes(model.modelName);
        const uACR = isCM ? await isEnabled(FeatureFlag.USE_ADMIN_CATALOG_READS) : false;
        const uACS = isCM ? await isEnabled(FeatureFlag.ENABLE_ATLAS_CATALOG_SEARCH) : false;
        let ck: string | null = null;

        if (isCM) {
            const sq = Object.keys(eq).sort().map(k => `${k}=${encodeURIComponent(String(eq[k]))}`).join('&');
            ck = `catalog:list:${model.modelName.toLowerCase()}:${isUrlAdmin ? 'admin' : 'public'}:${uACR ? 'admin-read' : 'user-read'}:${req.path}?${sq}`;
            const cp = await getCache<any>(ck);
            if (cp) {
                const etag = `W/"${Buffer.from(JSON.stringify(cp)).toString('base64').substring(0, 24)}"`;
                res.setHeader('ETag', etag);
